INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_M199", 1001, "2020-02-15 15:00:00", "", "bgm_M199_juke", 1002, "お兄ちゃん争奪！\nどっちのチョコがおいしいでSHOW", "2030/12/31 15:00:00", "愛情たっぷりのチョコレートケー\nキを完成させよう！\n超キュートなタップゲーム！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_M227", 1002, "2020-02-15 15:00:00", "", "bgm_M227_juke", 1003, "クウカ大回転\n飛行道中エクスタシー", "2030/12/31 15:00:00", "大回転！クウカ！\n最高のエクスタシーここにあり！\n引っ張って飛ばす、空の旅！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_M249", 1003, "2020-02-15 15:00:00", "", "bgm_M249_juke", 1004, "カオリのマブイ式空手道場", "2030/12/31 15:00:00", "これぞ琉球魂！\n押し寄せるマジムンをなぎ倒す\n爽快アクションゲーム！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_M277", 1004, "2020-02-15 15:00:00", "", "bgm_M277_juke", 1005, "大激戦！しりとりドラゴンズ", "2030/12/31 15:00:00", "白熱バトル！\nドラゴンズネスト流\nタイマン式頭脳しりとり！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_M355_Lofi", 1005, "2020-05-31 12:00:00", "", "bgm_M355_Lofi_juke", 1006, "チュウチュウパニック！\nチーズお守り大作戦！", "2030/12/31 15:00:00", "キミはチーズを守り抜けるか！？\n瞬発力が試される\n反射神経系カジュアルゲーム！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_M399", 1006, "2020-08-15 15:00:00", "", "bgm_M399", 1007, "猛訓打撃道！\nミサトのホームランドリル", "2030/12/31 15:00:00", "目指せホームランバッター！\nミートタイミングがカギを握る\nスポーツアクションゲーム！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_M500", 1007, "2021-08-31 12:00:00", "", "bgm_M500", 1008, "カルミナサマーライブ\nライブ会場 グッズエリア", "2030/12/31 15:00:00", "カルミナファン大興奮！\nライブ応援グッズを手に入れて\n目指せ「カルミナ神推し」！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_M540", 1008, "2021-12-18 15:00:00", "", "bgm_M540", 1009, "ミヤコ's キッチン　究極への道", "2030/12/31 15:00:00", "レッツ・クッキング！\nミヤコとプリンを作って食べて\nプリンの道を極めよう！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (0, "2022/02/28 11:59:59", "bgm_M569", 1009, "2022-02-15 15:00:00", "ランドソルクイズコネクト！", "bgm_M569", 1010, "Happy Anniv.スペシャル　\nランドソルクイズコネクト！", "2022/02/15 15:00:00", "５人チームで力を合わせて多種多\n様なジャンルのクイズに挑戦！\n目指せ、クイズプリンセス！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_M605", 1010, "2022-07-18 15:00:00", "", "bgm_M605", 1011, "駆けろ常夏！\nアルティメットビーチフラッグス", "2030/12/31 15:00:00", "砂浜駆けるプリンセス！\nハチャメチャなコースに挑む、\n南の島のビーチフラッグス！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_MC068", 1012, "2023-09-18 15:00:00", "放課後クイズエデュケーション　{0}", "bgm_MC068", 1012, "キャルとスズナの\n放課後クイズエデュケーション", "2030/12/31 15:00:00", "めざせ全問正解！\nキャルとスズナと放課後の教室で\n二人きりのクイズ勉強会！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_MC141", 1013, "2024-04-18 15:00:00", "行軍（マーチ）A-Go-Go！", "bgm_MC141", 1013, "エリコとマコトの\n行軍（マーチ）A-Go-Go！", "2030/12/31 15:00:00", "魔物はびこる街道を突き進め！\n【王宮騎士団(NIGHTMARE)】\nの兵たちを率い、訓練に挑戦だ！");
INSERT INTO `v1_ba50002facee27f1cdd2955d06f745e5b31937bb95707b850fcf3adf3db15a8c` VALUES (10000, "2030/12/31 15:00:00", "bgm_MC199", 1014, "2024-11-18 15:00:00", "激突！破壊！\nイリーガルタンクウォー", "bgm_MC199_Battle", 1014, "激突！破壊！\nイリーガルタンクウォー", "2030/12/31 15:00:00", "戦車バトル大会開幕！\n組み上げたオリジナルマシンで\n頂点を目指せ！");
